#include <stdio.h>
int main() {
    int T, N, X, S, A, B;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &X, &S);
        int pos = X;
        for (int i = 0; i < S; i++) {
            scanf("%d %d", &A, &B);
            if (pos == A) pos = B;
            else if (pos == B) pos = A;
        }
        printf("%d\n", pos);
    }
    return 0;
}

